@page "/chat"
@rendermode InteractiveServer
@using sv_78a37f739f7b4b1e8a8f493e5c6a8e68.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var ch in channels)
                {
                    <li class="channel-item @(ch.Id == activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-name-row">
                            <span class="channel-name"># @ch.Name</span>
                            @if (ch.UnreadCount > 0)
                            {
                                <span class="unread-badge">@ch.UnreadCount</span>
                            }
                        </div>
                        <span class="channel-desc">@Truncate(ch.Description, 40)</span>
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="message-area @(threadOpen ? "thread-open" : "")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h2># @activeChannel.Name</h2>
                <span class="header-desc">@activeChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="OnMessageScroll" @ref="messageListRef">
                @if (loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (messages is not null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message-card" @onmouseenter="() => hoveredMessageId = msg.Id"
                             @onmouseleave="() => hoveredMessageId = null">
                            <div class="message-meta">
                                <strong class="msg-author">@msg.Author</strong>
                                <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="msg-content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread starter link *@
                            @if (msg.ReplyToId is null && threadSummaries.TryGetValue(msg.Id, out var ts))
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @ts.ReplyCount @(ts.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }

                            @* Hover actions *@
                            @if (hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">
                                            😀 React
                                        </button>
                                        @if (emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => ReactAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea class="compose-input" placeholder="Message #@activeChannel.Name"
                          @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="OnComposeKeyDown" />
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(newMessageText)"
                        @onclick="SendMessageAsync">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <strong>@threadRootMessage.Author</strong>
                <span class="msg-time">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                <p>@threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @if (threadMessages is not null)
                {
                    @foreach (var reply in threadMessages)
                    {
                        <div class="message-card thread-reply">
                            <div class="message-meta">
                                <strong class="msg-author">@reply.Author</strong>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge"
                                                title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="compose-area">
                <textarea class="compose-input" placeholder="Reply…"
                          @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown" />
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(threadReplyText)"
                        @onclick="SendThreadReplyAsync">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    // Data
    private List<Channel>? channels;
    private List<Message>? messages;
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private List<Message>? threadMessages;

    // State
    private int? activeChannelId;
    private Channel? activeChannel;
    private int skip;
    private bool loadingOlder;
    private bool allOlderLoaded;
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private string newMessageText = string.Empty;

    // Thread state
    private bool threadOpen;
    private Message? threadRootMessage;
    private string threadReplyText = string.Empty;

    private ElementReference messageListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannelId = channel.Id;
        activeChannel = channel;
        skip = 0;
        allOlderLoaded = false;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        skip = messages.Count;
        await BuildThreadSummariesAsync();
        await ChatService.MarkChannelReadAsync(channel.Id);
        RefreshChannelUnread(channel.Id);
        CloseThread();
    }

    private async Task BuildThreadSummariesAsync()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        // Identify root messages that have replies (messages where other messages reference them)
        var rootIds = messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct();

        foreach (var rootId in rootIds)
        {
            var thread = await ChatService.GetThreadAsync(rootId);
            if (thread.Count > 0)
            {
                threadSummaries[rootId] = new ThreadSummary(
                    rootId,
                    thread.Count,
                    thread.Max(t => t.SentAt));
            }
        }

        // Also check each top-level message for threads
        foreach (var msg in messages.Where(m => m.ReplyToId is null && !threadSummaries.ContainsKey(m.Id)))
        {
            var thread = await ChatService.GetThreadAsync(msg.Id);
            if (thread.Count > 0)
            {
                threadSummaries[msg.Id] = new ThreadSummary(
                    msg.Id,
                    thread.Count,
                    thread.Max(t => t.SentAt));
            }
        }
    }

    private async Task OnMessageScroll()
    {
        // Scroll-to-top triggers loading older messages.
        // In a real app we'd read scrollTop via JS interop; here we use a simplified approach
        // that loads more messages when the user triggers the scroll event while not already loading.
        if (loadingOlder || allOlderLoaded || activeChannelId is null) return;

        // This is invoked on every scroll. A production implementation would check scrollTop === 0
        // via JS interop. For now, we expose the mechanism and rely on the UI affordance.
    }

    /// <summary>
    /// Public method callable from JS interop or a "Load older" button to paginate.
    /// </summary>
    private async Task LoadOlderMessagesAsync()
    {
        if (loadingOlder || allOlderLoaded || activeChannelId is null) return;

        loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId.Value, skip, PageSize);
        if (older.Count == 0)
        {
            allOlderLoaded = true;
        }
        else
        {
            messages = [..older, ..(messages ?? [])];
            skip += older.Count;
        }

        loadingOlder = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannelId.Value, newMessageText.Trim(), null);
        messages ??= [];
        messages.Add(sent);
        skip++;
        newMessageText = string.Empty;
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        threadOpen = true;
        threadReplyText = string.Empty;
        emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = null;
        threadReplyText = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannelId is null)
            return;

        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, threadReplyText.Trim(), threadRootMessage.Id);
        threadMessages ??= [];
        threadMessages.Add(reply);
        threadReplyText = string.Empty;

        // Update the thread summary count
        if (threadSummaries.TryGetValue(threadRootMessage.Id, out var existing))
        {
            threadSummaries[threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to reflect the new reaction
        if (activeChannelId is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannelId.Value, 0, skip > 0 ? skip : PageSize);
        }

        // Refresh thread if open
        if (threadOpen && threadRootMessage is not null)
        {
            threadMessages = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task OnComposeKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    private void RefreshChannelUnread(int channelId)
    {
        if (channels is null) return;
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    // Helpers

    private static string Truncate(string text, int maxLen) =>
        text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

