+    {
+        // Scroll-to-top triggers loading older messages.
+        // In a real app we'd read scrollTop via JS interop; here we use a simplified approach
+        // that loads more messages when the user triggers the scroll event while not already loading.
+        if (loadingOlder || allOlderLoaded || activeChannelId is null) return;
+
+        // This is invoked on every scroll. A production implementation would check scrollTop === 0
+        // via JS interop. For now, we expose the mechanism and rely on the UI affordance.
+    }
+
+    /// <summary>
+    /// Public method callable from JS interop or a "Load older" button to paginate.
+    /// </summary>
+    private async Task LoadOlderMessagesAsync()
+    {
+        if (loadingOlder || allOlderLoaded || activeChannelId is null) return;
+
+        loadingOlder = true;
+        StateHasChanged();
+
+        var older = await ChatService.GetMessagesAsync(activeChannelId.Value, skip, PageSize);
+        if (older.Count == 0)
+        {
+            allOlderLoaded = true;
+        }
+        else
+        {
+            messages = [..older, ..(messages ?? [])];
+            skip += older.Count;
+        }
+
+        loadingOlder = false;
+    }
+
+    private async Task SendMessageAsync()
+    {
+        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannelId is null) return;
+
+        var sent = await ChatService.SendMessageAsync(activeChannelId.Value, newMessageText.Trim(), null);
+        messages ??= [];
+        messages.Add(sent);
+        skip++;
+        newMessageText = string.Empty;
+    }
+
+    private async Task OpenThreadAsync(Message rootMessage)
+    {
+        threadRootMessage = rootMessage;
+        threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
+        threadOpen = true;
+        threadReplyText = string.Empty;
+        emojiPickerMessageId = null;
+    }
+
+    private void CloseThread()
+    {
+        threadOpen = false;
+        threadRootMessage = null;
+        threadMessages = null;
+        threadReplyText = string.Empty;
+    }
+
+    private async Task SendThreadReplyAsync()
+    {
+        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannelId is null)
+            return;
+
+        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, threadReplyText.Trim(), threadRootMessage.Id);
+        threadMessages ??= [];
+        threadMessages.Add(reply);
+        threadReplyText = string.Empty;
+
+        // Update the thread summary count
+        if (threadSummaries.TryGetValue(threadRootMessage.Id, out var existing))
+        {
+            threadSummaries[threadRootMessage.Id] = existing with
+            {
+                ReplyCount = existing.ReplyCount + 1,
+                LastReplyAt = reply.SentAt
+            };
+        }
+        else
+        {
+            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, reply.SentAt);
+        }
+    }
+
+    private async Task ReactAsync(int messageId, string emoji)
+    {
+        await ChatService.AddReactionAsync(messageId, emoji);
+        emojiPickerMessageId = null;
+
+        // Refresh messages to reflect the new reaction
+        if (activeChannelId is not null)
+        {
+            messages = await ChatService.GetMessagesAsync(activeChannelId.Value, 0, skip > 0 ? skip : PageSize);
+        }
+
+        // Refresh thread if open
+        if (threadOpen && threadRootMessage is not null)
+        {
+            threadMessages = await ChatService.GetThreadAsync(threadRootMessage.Id);
+        }
+    }
+
+    private void ToggleEmojiPicker(int messageId)
+    {
+        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
+    }
+
+    private async Task OnComposeKeyDown(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendMessageAsync();
+        }
+    }
+
+    private async Task OnThreadKeyDown(KeyboardEventArgs e)
+    {
+        if (e is { Key: "Enter", ShiftKey: false })
+        {
+            await SendThreadReplyAsync();
+        }
+    }
+
+    private void RefreshChannelUnread(int channelId)
+    {
+        if (channels is null) return;
+        var idx = channels.FindIndex(c => c.Id == channelId);
+        if (idx >= 0)
+        {
+            channels[idx] = channels[idx] with { UnreadCount = 0 };
+        }
+    }
+
+    // Helpers
+
+    private static string Truncate(string text, int maxLen) =>
+        text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt;
+        if (diff.TotalSeconds < 60) return "just now";
+        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
+        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
+        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
+        return sentAt.ToString("MMM d, yyyy");
+    }
+}
